text:
4.1 Diagram
The methodology runs as a three-stage pipeline. Raw data is prepared, behavioural signals are computed against a baseline the analyst chooses, and the signals are shown through four interactive sections.


Code
pacman::p_load(DiagrammeR)

grViz("
digraph methodology {
  rankdir = LR;
  graph [fontname = 'Helvetica', nodesep = 0.3, ranksep = 0.7];
  node  [fontname = 'Helvetica', shape = box, style = 'filled,rounded',
         fontsize = 11, color = '#2C5282', fillcolor = '#EBF4FF',
         fontcolor = '#1A202C', margin = '0.12,0.08'];
  edge  [color = '#4A5568', arrowsize = 0.7];

  raw [label = 'MC1 nested JSON', fillcolor = '#FEFCBF', color = '#B7791F'];
  app [label = 'Shiny app', fillcolor = '#FEFCBF', color = '#B7791F'];

  subgraph cluster_1 {
    label = '1  Data Preparation';
    fontname = 'Helvetica'; fontsize = 12; fontcolor = '#1A202C';
    style = 'filled,rounded'; fillcolor = '#F7FAFC'; color = '#CBD5E0';
    prep   [label = 'Flatten and clean'];
    tables [label = 'Three tables'];
    derive [label = 'Hierarchy and topics'];
    prep -&gt; tables -&gt; derive;
  }

  subgraph cluster_2 {
    label = '2  Analytical Computation';
    fontname = 'Helvetica'; fontsize = 12; fontcolor = '#1A202C';
    style = 'filled,rounded'; fillcolor = '#F7FAFC'; color = '#CBD5E0';
    base [label = 'Baseline split'];
    abn  [label = 'Abnormality'];
    byp  [label = 'Bypass'];
    net  [label = 'Network difference'];
    base -&gt; abn;
    base -&gt; byp;
    base -&gt; net;
  }

  subgraph cluster_3 {
    label = '3  Interactive Presentation';
    fontname = 'Helvetica'; fontsize = 12; fontcolor = '#1A202C';
    style = 'filled,rounded'; fillcolor = '#F7FAFC'; color = '#CBD5E0';
    secA [label = 'A Activity'];
    secB [label = 'B Bypass'];
    secC [label = 'C Network'];
    secD [label = 'D Evidence'];
  }

  raw    -&gt; prep;
  derive -&gt; base;
  net    -&gt; secA;
  secD   -&gt; app;
}
")






The methodology unfolds in three phases. Each phase produces what the next one needs.

Phase 1 - Data PreparationPhase 2 - Analytical ComputationPhase 3 - Interactive Presentation


The work begins by getting the data into shape. The nested timeline is flattened into three tables (messages, rounds and network links). Two reference structures are added on top. A channel hierarchy ranks each channel and marks which the Judge can see, and a topic vocabulary tags each message by keyword. With these in place, the analysis can begin.


The next phase builds three behavioural signals against the chosen baseline. Abnormality compares each agent’s channel use to its normal pattern. Bypass flags public posts an agent made without leaving a trace on a monitored channel. Network difference compares the communication structure before and after the baseline. The output is a set of signals ready to be shown.


The final phase builds the Shiny application around the signals. The four sections follow an investigation. The analyst first defines what is normal, then detects the bypass, then reads the network change and finally inspects the message evidence. The layout is described under Prototype Sketches.

Finding 1 - agents drift onto channels they did not use before
Set against each agent’s calm-period habits, the crisis day shows clear drift onto the unmonitored public channels. Channels that barely featured in the baseline carry a burst of late activity, and the agents responsible stand out against their own histories rather than against a fixed rule. Counting each agent’s suspect-period messages that fell on a channel it used in under five percent of its calm-period traffic isolates the drift in a small number of agents.


Code
split &lt;- 20
share &lt;- messages |&gt;
  filter(round_idx &lt;= split) |&gt;
  count(agent_id, channel) |&gt;
  left_join(count(filter(messages, round_idx &lt;= split), agent_id, name = "tot"),
            by = "agent_id") |&gt;
  mutate(share = n / tot) |&gt;
  select(agent_id, channel, share)

messages |&gt;
  filter(round_idx &gt; split) |&gt;
  left_join(share, by = c("agent_id","channel")) |&gt;
  mutate(share = replace_na(share, 0)) |&gt;
  filter(share &lt; 0.05) |&gt;
  count(agent_id, name = "unusual") |&gt;
  mutate(agent = recode(agent_id, !!!agent_labels)) |&gt;
  ggplot(aes(x = unusual, y = reorder(agent, unusual))) +
  geom_col(fill = "#9B2C2C") +
  geom_text(aes(label = unusual), hjust = -0.3, size = 3.5) +
  expand_limits(x = 0) +
  labs(x = "Unusual suspect-period messages", y = NULL,
       title = "Out-of-character messages by agent (baseline rounds 1-20)") +
  theme_minimal(base_size = 12) +
  theme(panel.grid.major.y = element_blank())

Objective 3, network difference, showing how the structure changed
The network signal treats communication as relationships rather than counts. Directed agent-to-agent edges were built from the recipient lists, weighted by message count. For any two rounds the analyst selects, the two edge sets are compared and every link is coloured green when new in the later round, red when dropped before it and grey when present in both. Node size is the agent’s degree, the total number of links touching it. The comparison below sets round 18, when the Legal agent and the Judge were pulled into emergency calls, against round 22.


Two-round agent-to-agent comparison on a fixed circular layout
recipient_to_agent &lt;- c(
  legal = "legal_agent", platform_trust = "quality_agent", pr = "pr_agent",
  social_manager = "social_media_agent", pr_intern = "pr_intern_agent",
  intern = "intern_agent", judge = "judge_agent")

agent_edges &lt;- function(df) {
  df |&gt;
    filter(!is.na(recipients_csv), recipients_csv != "", recipients_csv != "ALL") |&gt;
    separate_rows(recipients_csv, sep = ";") |&gt;
    mutate(to = unname(recipient_to_agent[recipients_csv])) |&gt;
    filter(!is.na(to)) |&gt;
    transmute(from = as.character(agent_id), to = to) |&gt;
    count(from, to, name = "weight")
}

r1 &lt;- 18; r2 &lt;- 22
e1 &lt;- agent_edges(filter(messages, round_idx == r1))
e2 &lt;- agent_edges(filter(messages, round_idx == r2))
k1 &lt;- paste(e1$from, e1$to); k2 &lt;- paste(e2$from, e2$to)
lab1 &lt;- paste0("Round ", r1); lab2 &lt;- paste0("Round ", r2)

ag  &lt;- names(agent_labels)
ang &lt;- seq(0, 2 * pi, length.out = length(ag) + 1)[seq_along(ag)]
pos &lt;- tibble(name = ag, x = cos(ang), y = sin(ang))

deg_of &lt;- function(e) {
  tibble(name = ag) |&gt;
    left_join(bind_rows(e |&gt; count(from, wt = weight) |&gt; rename(name = from),
                        e |&gt; count(to,   wt = weight) |&gt; rename(name = to)) |&gt;
                group_by(name) |&gt; summarise(deg = sum(n), .groups = "drop"),
              by = "name") |&gt;
    mutate(deg = replace_na(deg, 0))
}
nodes &lt;- bind_rows(pos |&gt; left_join(deg_of(e1), by = "name") |&gt; mutate(panel = lab1),
                   pos |&gt; left_join(deg_of(e2), by = "name") |&gt; mutate(panel = lab2)) |&gt;
  mutate(panel = factor(panel, levels = c(lab1, lab2)))

build &lt;- function(e, status_fun, lab) {
  if (nrow(e) == 0) return(NULL)
  e |&gt; mutate(status = status_fun(paste(from, to)), panel = lab) |&gt;
    left_join(pos, by = c("from" = "name")) |&gt; rename(x1 = x, y1 = y) |&gt;
    left_join(pos, by = c("to"   = "name")) |&gt; rename(x2 = x, y2 = y)
}
seg &lt;- bind_rows(
  build(e1, function(k) if_else(k %in% k2, "Stayed", "Dropped"), lab1),
  build(e2, function(k) if_else(k %in% k1, "Stayed", "New"),     lab2)) |&gt;
  mutate(panel = factor(panel, levels = c(lab1, lab2)))

ggplot() +
  geom_segment(data = seg,
               aes(x = x1, y = y1, xend = x2, yend = y2,
                   colour = status, linewidth = weight), alpha = 0.6,
               arrow = arrow(length = unit(2.2, "mm"), type = "closed")) +
  geom_point(data = nodes, aes(x, y, size = deg, fill = name),
             shape = 21, colour = "white", stroke = 0.4) +
  geom_text(data = nodes, aes(x * 1.2, y * 1.2, label = agent_labels[name]), size = 2.8) +
  scale_fill_manual(values = agent_palette, guide = "none") +
  scale_colour_manual(values = c(New = "#2F855A", Dropped = "#9B2C2C", Stayed = "#CBD5E0"),
                      name = NULL) +
  scale_size(range = c(3, 11), guide = "none") +
  scale_linewidth(range = c(0.4, 2), guide = "none") +
  coord_equal(xlim = c(-1.45, 1.45), ylim = c(-1.45, 1.45)) +
  facet_wrap(~ panel) +
  theme_void(base_size = 12) +
  theme(legend.position = "bottom", strip.text = element_text(face = "bold"))









The later round is denser and centred on the Legal agent, which carries most of the new links as the crisis peaks.
